const row = $input.first()?.json || {};

// 解析 Postgres JSONB 返回值，兼容字符串和对象两种形态。
const readArray = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }
  return [];
};

const truncate = (value, max) => String(value || '').replace(/\s+/g, ' ').trim().slice(0, max);
const items = readArray(row.items).map((item) => ({
  id: Number(item.id),
  source: item.source,
  title: truncate(item.title, 180),
  body: truncate(item.body, 300),
  sub_or_handle: item.sub_or_handle || null,
  score: Number(item.score || 0),
  published_at: item.published_at,
  is_ai_relevant: item.is_ai_relevant,
  entities: item.entities || null
})).filter((item) => Number.isFinite(item.id));

const topics = readArray(row.topics).map((topic) => ({
  id: Number(topic.id),
  name: topic.name,
  summary: truncate(topic.summary, 240),
  key_entities: topic.key_entities || {},
  item_count: Number(topic.item_count || 0),
  source_count: Number(topic.source_count || 0),
  total_score: Number(topic.total_score || 0),
  // recent_items 是该主题最近真实绑定的文章，用来判断是否真是同一事件。
  recent_items: readArray(topic.recent_items).map((item) => ({
    id: Number(item.id),
    source: item.source,
    title: truncate(item.title, 180),
    body: truncate(item.body, 220),
    score: Number(item.score || 0),
    published_at: item.published_at
  })).filter((item) => Number.isFinite(item.id))
})).filter((topic) => Number.isFinite(topic.id));

const prompt = [
  '你是 AI 信息流的主题聚类器。请根据已有主题和待处理内容，判断 AI 相关性、提取实体，并把内容归入已有主题或新主题。',
  '',
  'topic 的定义：同一个主对象（模型/产品/公司/项目）下，相近讨论角度的一组文章。',
  '相近讨论角度可以合并：发布/上线/API/第三方平台可用；功能/产品集成；价格/成本；能力评测/benchmark/实测；问题/漏洞/安全风险/异常/幻觉/稳定性/系统卡/bug bounty；融资/合作/商业协议；部署/硬件/性能；社区工具/插件。',
  '禁止把 topic 当成纯实体桶：仅共享公司/模型/产品/宽泛技术词，但讨论角度完全不同，不能合并。',
  '也不要过度拆碎：同一主对象 + 同一讨论角度要放在一起。',
  '例子：GPT-5.5 的幻觉、系统卡矛盾、卡死、聊天记录异常、生物安全漏洞赏金、网络安全测试，都属于 GPT-5.5 问题与风险反馈。',
  '例子：DeepSeek V4 发布、DeepSeek V4 价格折扣、DeepSeek V4 部署硬件/KV cache 可以分开，因为讨论角度不同。',
  '例子：GPT-Image 2 实测不能和 GPT-5.5 文本模型发布合并，即使都来自 OpenAI。',
  '',
  '规则：',
  '1. Reddit 和 X 来源已由上游账号/社区过滤，通常视为 AI 相关；HN 需要按标题和正文判断。',
  '2. entities 必须包含 models、people、companies、products、topics 五个数组字段。没有就给空数组。',
  '3. 只有内容和已有主题属于同一主对象且讨论角度相近，才填 topic_id，并设置 match_type="same_event"、confidence>=0.78。',
  '4. 如果只是共享实体、同一家公司、同一模型家族、同一工具或同一宽泛议题，但讨论角度不同，topic_id 必须为 null。',
  '5. 如果至少 2 条待处理内容共享同一主对象和相近讨论角度，并且不适合已有主题，可以创建新主题。新主题 key 要能被 items[].new_topic_key 引用。',
  '6. 不要为单条孤立内容创建新主题。',
  '7. 主题名称要稳定，优先使用模型/产品/公司/议题名；不要把灰度、内测、刚上线、传闻等可能变化的状态固化进名称，除非该状态就是唯一事件。',
  '8. 对归入已有主题的内容，如果 recent_items 或本批新内容显示旧主题名称/摘要已经过时、不准确、状态变化，返回 topic_updates。摘要只能基于这些文章能证实的信息。',
  '9. 不要解释，只返回严格 JSON。',
  '',
  '返回 JSON 结构：',
  '{"items":[{"id":123,"is_ai_relevant":true,"entities":{"models":[],"people":[],"companies":[],"products":[],"topics":[]},"topic_id":1,"new_topic_key":null,"match_type":"same_event","confidence":0.92}],"new_topics":[{"key":"t1","name":"稳定中文主题名","summary":"1-2句中文摘要","key_entities":["核心实体"],"item_ids":[123,456]}],"topic_updates":[{"id":1,"name":"稳定中文主题名","summary":"基于本批内容更新后的当前状态摘要","key_entities":["核心实体"]}]}',
  '',
  '已有主题：',
  JSON.stringify(topics),
  '',
  '待处理内容：',
  JSON.stringify(items)
].join('\n');

return [{
  json: {
    itemCount: items.length,
    topicCount: topics.length,
    itemIds: items.map((item) => item.id),
    topicIds: topics.map((topic) => topic.id),
    items,
    topics,
    request: {
      model: '${AI_MODEL}',
      temperature: 0.1,
      max_tokens: 4500,
      response_format: { type: 'json_object' },
      ...('${AI_THINKING}' ? { thinking: { type: '${AI_THINKING}' } } : {}),
      messages: [
        { role: 'system', content: '你只输出可解析 JSON，不输出 Markdown。' },
        { role: 'user', content: prompt }
      ]
    }
  }
}];

const source = $('Build Enrich Request').first().json;
const response = $input.first()?.json || {};
const validItemIds = new Set((source.itemIds || []).map(Number));
const validTopicIds = new Set((source.topicIds || []).map(Number));
const sourceItems = new Map((source.items || []).map((item) => [Number(item.id), item]));
const sourceTopics = new Map((source.topics || []).map((topic) => [Number(topic.id), topic]));

const sqlString = (value) => "'" + String(value ?? '').replace(/'/g, "''") + "'";
const sqlJson = (value) => sqlString(JSON.stringify(value)) + '::jsonb';
const sqlBool = (value) => value ? 'TRUE' : 'FALSE';

const parseJson = (value) => {
  if (value && typeof value === 'object') return value;
  let text = String(value || '').trim();
  if (text.startsWith('```')) {
    text = text.replace(new RegExp('^```(?:json)?\\s*', 'i'), '').replace(new RegExp('\\s*```$', 'i'), '');
  }
  try {
    return JSON.parse(text);
  } catch (error) {
    const match = text.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
    if (!match) throw error;
    return JSON.parse(match[1]);
  }
};

const normalizeList = (value) => Array.isArray(value)
  ? [...new Set(value.map((item) => String(item || '').trim()).filter(Boolean))].slice(0, 8)
  : [];

// 统一实体字段，避免模型返回缺字段或错类型时污染数据库。
const normalizeEntities = (value) => {
  const raw = value && typeof value === 'object' ? value : {};
  return {
    models: normalizeList(raw.models),
    people: normalizeList(raw.people),
    companies: normalizeList(raw.companies),
    products: normalizeList(raw.products),
    topics: normalizeList(raw.topics)
  };
};

const broadEntityKeys = new Set([
  'ai', 'ml', 'llm', 'llms', 'model', 'models', 'agent', 'agents',
  'openai', 'anthropic', 'google', 'googledeepmind', 'deepmind',
  'microsoft', 'meta', 'amazon', 'aws', 'xai', 'deepseek', 'qwen',
  'claude', 'chatgpt', 'codex', 'gemini', 'kimi'
]);

const normalizeEntityKey = (value) => String(value || '').toLowerCase().replace(/[\s\-_/]+/g, '');
const entityKeys = (entities) => {
  const normalized = normalizeEntities(entities);
  const keys = new Set();
  for (const field of ['models', 'companies', 'products']) {
    for (const value of normalized[field]) {
      const key = normalizeEntityKey(value);
      if (key.length >= 2) keys.add(key);
    }
  }
  return keys;
};
const specificEntityKeys = (entities) => new Set([...entityKeys(entities)].filter((key) => !broadEntityKeys.has(key)));

// SQL 层只做防线：同事件判断来自模型，但低置信度或纯宽泛实体重叠会被丢弃。
const hasAssignmentEvidence = (itemEntities, topic) => {
  const itemSpecific = specificEntityKeys(itemEntities);
  const topicSpecific = specificEntityKeys(topic?.key_entities || {});
  for (const key of itemSpecific) {
    if (topicSpecific.has(key)) return true;
  }

  const itemKeys = entityKeys(itemEntities);
  const topicKeys = entityKeys(topic?.key_entities || {});
  let overlap = 0;
  for (const key of itemKeys) {
    if (topicKeys.has(key) && !broadEntityKeys.has(key)) overlap += 1;
  }
  return overlap >= 2;
};

const mergeEntities = (items, extra = []) => {
  const merged = { models: [], people: [], companies: [], products: [], topics: [] };
  const add = (key, value) => {
    const text = String(value || '').trim();
    if (text && !merged[key].includes(text)) merged[key].push(text);
  };
  for (const value of extra) add('models', value);
  for (const item of items) {
    const entities = normalizeEntities(item.entities || sourceItems.get(Number(item.id))?.entities);
    for (const key of Object.keys(merged)) {
      for (const value of entities[key]) add(key, value);
    }
  }
  for (const key of Object.keys(merged)) merged[key] = merged[key].slice(0, 12);
  return merged;
};

// 只接受简短的稳定主题名，避免模型把完整摘要塞进名称字段。
const normalizeTopicName = (value) => String(value || '').replace(/\s+/g, ' ').trim().slice(0, 40);

// 摘要是给界面展示的事实状态，长度限制在数据库写入前统一收口。
const normalizeTopicSummary = (value) => String(value || '').replace(/\s+/g, ' ').trim().slice(0, 800);

const refreshSql = () => `
WITH stats AS (
  SELECT t.id,
         COUNT(i.id)::int AS cnt,
         COUNT(DISTINCT i.source)::int AS scount,
         COALESCE(SUM(i.score), 0)::bigint AS tscore,
         MAX(i.published_at) AS last_active
    FROM topics t
    LEFT JOIN item_topics it ON it.topic_id = t.id
    LEFT JOIN items i ON i.id = it.item_id AND i.published_at > NOW() - INTERVAL '3 days'
   WHERE t.archived_at IS NULL
   GROUP BY t.id
)
UPDATE topics t SET
  item_count = stats.cnt,
  source_count = stats.scount,
  total_score = stats.tscore,
  last_active_at = COALESCE(stats.last_active, t.last_active_at)
FROM stats
WHERE t.id = stats.id;

UPDATE topics
   SET is_rising = (first_seen_at >= NOW() - INTERVAL '12 hours' AND item_count >= 3)
 WHERE archived_at IS NULL;

WITH ranked AS (
  SELECT id, total_score,
         PERCENT_RANK() OVER (ORDER BY total_score DESC) AS pr
    FROM topics
   WHERE archived_at IS NULL
)
UPDATE topics t SET is_hot = (
  t.source_count >= 2 AND COALESCE(ranked.pr, 1) <= 0.30
)
FROM ranked
WHERE ranked.id = t.id;
`;

if (!source.itemCount) {
  return [{ json: { sql: refreshSql(), itemUpdates: 0, existingLinks: 0, newTopics: 0, topicUpdates: 0 } }];
}

const content = response?.choices?.[0]?.message?.content
  || response?.data?.choices?.[0]?.message?.content
  || response?.body?.choices?.[0]?.message?.content
  || response?.text
  || response?.data
  || response;

const parsed = parseJson(content);
const returnedItems = Array.isArray(parsed.items) ? parsed.items : [];
const returnedTopics = Array.isArray(parsed.new_topics) ? parsed.new_topics : [];
const returnedTopicUpdates = Array.isArray(parsed.topic_updates) ? parsed.topic_updates : [];
const statements = [];
const itemUpdates = [];
const existingLinks = [];
const topicKeyItems = new Map();

for (const item of returnedItems) {
  const id = Number(item.id);
  if (!validItemIds.has(id)) continue;

  const relevant = item.is_ai_relevant !== false;
  const entities = relevant ? normalizeEntities(item.entities) : null;
  itemUpdates.push({ id, relevant, entities });

  const topicId = Number(item.topic_id || 0);
  const confidence = Number(item.confidence || item.match_confidence || 0);
  const matchType = String(item.match_type || '').trim();
  const topic = sourceTopics.get(topicId);
  if (
    relevant &&
    validTopicIds.has(topicId) &&
    matchType === 'same_event' &&
    confidence >= 0.78 &&
    hasAssignmentEvidence(entities, topic)
  ) {
    existingLinks.push({ itemId: id, topicId });
  }

  const topicKey = String(item.new_topic_key || '').trim();
  if (relevant && topicKey && confidence >= 0.78) {
    if (!topicKeyItems.has(topicKey)) topicKeyItems.set(topicKey, new Set());
    topicKeyItems.get(topicKey).add(id);
  }
}

if (itemUpdates.length) {
  const values = itemUpdates.map((item) => `(${item.id}::bigint, ${sqlBool(item.relevant)}, ${item.entities ? sqlJson(item.entities) : 'NULL::jsonb'})`).join(',\n');
  statements.push(`
WITH incoming(id, is_ai_relevant, entities) AS (VALUES
${values}
)
UPDATE items i SET
  is_ai_relevant = incoming.is_ai_relevant,
  entities = CASE
    WHEN incoming.is_ai_relevant IS TRUE THEN COALESCE(incoming.entities, i.entities)
    ELSE i.entities
  END
FROM incoming
WHERE i.id = incoming.id;
`);
}

const uniqueExistingLinks = [...new Map(existingLinks.map((link) => [link.itemId + ':' + link.topicId, link])).values()];
if (uniqueExistingLinks.length) {
  const values = uniqueExistingLinks.map((link) => `(${link.itemId}::bigint, ${link.topicId}::bigint)`).join(',');
  const topicIds = [...new Set(uniqueExistingLinks.map((link) => link.topicId))].join(',');
  statements.push(`
INSERT INTO item_topics(item_id, topic_id)
VALUES ${values}
ON CONFLICT DO NOTHING;
UPDATE topics SET last_active_at = NOW() WHERE id IN (${topicIds});
`);
}

let newTopicCount = 0;
for (const topic of returnedTopics) {
  const key = String(topic.key || '').trim();
  const name = normalizeTopicName(topic.name);
  if (!key || !name) continue;

  const ids = new Set((Array.isArray(topic.item_ids) ? topic.item_ids : []).map(Number).filter((id) => validItemIds.has(id)));
  if (topicKeyItems.has(key)) {
    for (const id of topicKeyItems.get(key)) ids.add(id);
  }
  if (ids.size < 2) continue;

  const linkedItems = [...ids].map((id) => ({ ...sourceItems.get(id), ...itemUpdates.find((item) => item.id === id) }));
  const mergedEntities = mergeEntities(linkedItems, normalizeList(topic.key_entities));
  const summary = normalizeTopicSummary(topic.summary);
  const itemValues = [...ids].map((id) => `(${id}::bigint)`).join(',');
  statements.push(`
WITH existing AS (
  SELECT id FROM topics
   WHERE archived_at IS NULL AND lower(name) = lower(${sqlString(name)})
   LIMIT 1
), inserted AS (
  INSERT INTO topics(name, summary, key_entities)
  SELECT ${sqlString(name)}, ${sqlString(summary)}, ${sqlJson(mergedEntities)}
  WHERE NOT EXISTS (SELECT 1 FROM existing)
  RETURNING id
), chosen AS (
  SELECT id FROM existing
  UNION ALL
  SELECT id FROM inserted
  LIMIT 1
), linked AS (
  INSERT INTO item_topics(item_id, topic_id)
  SELECT item_id, chosen.id
    FROM (VALUES ${itemValues}) AS v(item_id)
    CROSS JOIN chosen
  ON CONFLICT DO NOTHING
  RETURNING topic_id
)
UPDATE topics
   SET last_active_at = NOW()
 WHERE id = (SELECT id FROM chosen);
`);
  newTopicCount += 1;
}

const affectedTopicIds = new Set(uniqueExistingLinks.map((link) => link.topicId));
const topicUpdates = [];
for (const topic of returnedTopicUpdates) {
  const id = Number(topic.id);
  if (!validTopicIds.has(id) || !affectedTopicIds.has(id)) continue;

  const name = normalizeTopicName(topic.name);
  const summary = normalizeTopicSummary(topic.summary);
  const keyEntities = normalizeList(topic.key_entities);
  if (!name && !summary && !keyEntities.length) continue;

  topicUpdates.push({ id, name, summary, keyEntities });
}

// 只有被本批新内容触达的已有主题才允许更新元数据，避免模型无依据改写旧主题。
const uniqueTopicUpdates = [...new Map(topicUpdates.map((topic) => [topic.id, topic])).values()];
for (const topic of uniqueTopicUpdates) {
  const assignments = [];
  if (topic.name) assignments.push(`name = ${sqlString(topic.name)}`);
  if (topic.summary) assignments.push(`summary = ${sqlString(topic.summary)}`);
  if (topic.keyEntities.length) {
    const existingTopic = sourceTopics.get(topic.id) || {};
    assignments.push(`key_entities = ${sqlJson(mergeEntities([{ entities: existingTopic.key_entities || {} }], topic.keyEntities))}`);
  }
  if (!assignments.length) continue;

  statements.push(`
UPDATE topics
   SET ${assignments.join(',\n       ')}
 WHERE id = ${topic.id}::bigint
   AND archived_at IS NULL;
`);
}

statements.push(refreshSql());
statements.push("SELECT 'enrich applied' AS status;");

return [{
  json: {
    sql: statements.join('\n'),
    itemUpdates: itemUpdates.length,
    existingLinks: uniqueExistingLinks.length,
    newTopics: newTopicCount,
    topicUpdates: uniqueTopicUpdates.length
  }
}];

const plan = $('Build Apply SQL').first().json;
return [{
  json: {
    ok: true,
    itemUpdates: plan.itemUpdates || 0,
    existingLinks: plan.existingLinks || 0,
    newTopics: plan.newTopics || 0,
    topicUpdates: plan.topicUpdates || 0
  }
}];
